// src/pages/Home.jsx  (or src/components/Home.jsx)
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import img1 from './images/download.jpeg';
import img2 from './images/images.jpeg';
import img3 from './images/photo-1437482078695-73f5ca6c96e2.avif';
import './Home.css'; // We'll add styles below

const Home = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const images = [
    { src: img1, alt: "Colorful Fish" },
    { src: img2, alt: "Tropical Aquarium" },
    { src: img3, alt: "Marine Life" }
  ];

  // Auto-slide every 3 seconds
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % images.length);
    }, 3000);
    return () => clearInterval(timer);
  }, [images.length]);

  const goToSlide = (index) => {
    setCurrentSlide(index);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + images.length) % images.length);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % images.length);
  };

  return (
    <div className="home-page">
      {/* Hero Section */}
      <div className='Navbar'>

      </div>


      <div className=''>
        <div id="carouselExampleIndicators" className="carousel slide">
          <ol className="carousel-indicators">
            {images.map((_, index) => (
              <li
                key={index}
                className={currentSlide === index ? "active" : ""}
                onClick={() => goToSlide(index)}
              ></li>
            ))}
          </ol>
          <div className="carousel-inner">
            {images.map((image, index) => (
              <div
                key={index}
                className={`carousel-item ${currentSlide === index ? "active" : ""}`}
              >
                <img className="d-block w-100" src={image.src} alt={image.alt} />
              </div>
            ))}
          </div>
          <button className="carousel-control-prev" onClick={prevSlide}>
            <span className="carousel-control-prev-icon" aria-hidden="true"></span>
            <span className="sr-only">Previous</span>
          </button>
          <button className="carousel-control-next" onClick={nextSlide}>
            <span className="carousel-control-next-icon" aria-hidden="true"></span>
            <span className="sr-only">Next</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Home;
